package io.github.njw3995.fabricmmo.core.info;

import java.io.BufferedReader;import java.io.IOException;import java.io.InputStream;import java.io.InputStreamReader;import java.io.UncheckedIOException;import java.nio.charset.StandardCharsets;import java.util.ArrayList;import java.util.List;import java.util.Locale;import java.util.Optional;
public final class SubSkillCatalog { private static final String RESOURCE="/fabricmmo/upstream-subskills-2.3.000.tsv";private static final SubSkillCatalog INSTANCE=load();private final List<SubSkillInfo> entries;private SubSkillCatalog(List<SubSkillInfo> e){entries=List.copyOf(e);}public static SubSkillCatalog instance(){return INSTANCE;}public List<SubSkillInfo> entries(){return entries;}public Optional<SubSkillInfo> find(String value){String n=value.replace("_","").replace(" ","").toLowerCase(Locale.ROOT);return entries.stream().filter(e->e.enumName().replace("_","").toLowerCase(Locale.ROOT).equals(n)||e.lookupName().toLowerCase(Locale.ROOT).equals(n)).findFirst();}private static SubSkillCatalog load(){InputStream in=SubSkillCatalog.class.getResourceAsStream(RESOURCE);if(in==null)throw new IllegalStateException("Missing "+RESOURCE);ArrayList<SubSkillInfo> e=new ArrayList<>();try(BufferedReader r=new BufferedReader(new InputStreamReader(in,StandardCharsets.UTF_8))){String l;while((l=r.readLine())!=null){if(l.isBlank()||l.startsWith("#"))continue;String[] c=l.split("\\t",-1);if(c.length!=5)throw new IOException("Invalid subskill row");e.add(new SubSkillInfo(c[0],c[1],c[2],Integer.parseInt(c[3]),Boolean.parseBoolean(c[4])));}}catch(IOException x){throw new UncheckedIOException(x);}return new SubSkillCatalog(e);}}
